external_knowledge:
- Leading educational institutions refer to universities that have been ranked highly; 
- The top tier in this context signifies universities with ranks 1 through 5; 
- The overall performance metrics represent the universities' overall scores.

sql:
SELECT university_name, country 
FROM universities 
WHERE overall_score = (SELECT MAX(overall_score) FROM universities);

SELECT DISTINCT universities.university_name, universities.country
FROM universities
INNER JOIN submitted_data ON universities.university_id = submitted_data.university_id;

SELECT university_name
FROM universities
WHERE overall_score > (SELECT overall_score FROM universities WHERE university_name = 'Cambridge');

SELECT university_id 
FROM graduate_prospects 
WHERE prospect_score > (SELECT AVG(prospect_score) FROM graduate_prospects);

SELECT u.university_name, u.overall_score
FROM universities u
WHERE u.rank <= 5 AND u.overall_score > (SELECT AVG(overall_score) FROM universities);

SELECT university_name
FROM universities
WHERE overall_score > (SELECT AVG(overall_score) FROM universities);

SELECT university_id, AVG(ATAN(satisfaction_score)) AS average_satisfaction_tangent
FROM student_satisfaction
GROUP BY university_id;

SELECT university_id, MAX(quality_score) AS HighestQualityScore
FROM research_metrics
GROUP BY university_id;

